    key_points: ["الإخلاص هو المحرك الأول لعلاج المخادعات؛ فمن كان الله همه كفاه الله شر نفسه.", "الصدق مع النفس يبدأ بالقدرة على الجلوس وحيداً دون مشتتات لمدة 15 دقيقة يومياً.", "تحميل \"الجن\" أو \"الظروف\" أخطاءك هو قمة الهروب النفسي من مسؤولية التزكية.", "مراتب الصدق تبدأ من الداخل؛ فإذا لم تعرف ما في باطنك فأنت في أول درجات النفاق.", "اليأس من مدح الخلق هو بوابة الحرية الحقيقية للوصول إلى الحق.", "قيام الليل هو أقوى أداة عملية لإسقاط هيبة الخلق من قلبك وترسيخ صدقك مع الخالق."],
    practical_applications: ["التزم بـ \"قيام الليل\" ولو بركعتين قبل الفجر لتجربة الانفراد بالخالق بعيداً عن أنظار الخلق.", "مارس \"الخلوة\" لمدة 10 دقائق يومياً دون هاتف أو كتاب، وراقب الأفكار التي تحاول الهرب منها.", "عندما تشعر برغبة في انتقاد شخص، اسأل نفسك: \"هل أنتقد لله أم لأغطي عيباً في نفسي؟\".", "توقف عن استخدام عبارة \"الإيمان في القلب\" لتبرير أي تقصير عملي تفعله اليوم.", "إذا سئلت عن شيء لا تعرفه، قل \"لا أعلم\" بوضوح لتدريب نفسك على الصدق وكسر كبرياء العلم.", "طبق \"أقل القليل\" من الأوراد اليومية (صلاة، ورد قرآن) لترسيخ الانضباط النفسي ومحاربة التسويه."],
