    key_points: ["الدماغ أداة مادية، والعقل عملية معنوية، والقلب هو موجه البوصلة.", "الناصية (الجبهة) هي مركز الإرادة، وتقويتها تكون بالتركيز والعبادة الواعية.", "الدوبامين يطلب اللذة اللحظية ويؤدي للإدمان، والسيروتونين يجلب السكينة والرضا.", "الذكر والأنثى مختلفان دماغياً؛ والمطالبة بالمساواة المطلقة تصادم الفطرة والبيولوجيا.", "الذاكرة لا تحفظ إلا ما يُعمل به؛ العمل هو الذي ينقل المعلومة للمستودع الدائم.", "المرونة العصبية تعني أن باب التغيير (التزكية) مفتوح دائماً عضوياً ونفسياً."],
    practical_applications: ["درب ناصيتك؛ مارس تمرين \"التركيز المطلق\" على عمل واحد لمدة 25 دقيقة دون تشتت.", "عزز السيروتونين؛ قم بعمل تطوعي أو خدمة لأهلك دون انتظار شكر؛ لتشعر بالرضا العميق.", "احمِ نومك؛ أخرج كل الشاشات من غرفة نومك، واجعل آخر مدخل لنفسك هو أذكار النوم.", "طبق قاعدة \"العلم بالعمل\"؛ كل معلومة نفسية تعلمتها اليوم، طبقها في موقف واحد غداً.", "راقب قلبك؛ عند قراءة القرآن، ركز على \"المعنى\" وليس فقط اللحن؛ لتفتح أقفال التدبر.", "افهم شريكك؛ قدري حاجته للتركيز في مهمة واحدة، وقدر حاجتها للتعبير عن انفعالاتها باللغة.", "الوثيقة 3 من."],
