    key_points: ["وراء كل فعل مصدر؛ ففتش في مصادرك تعرف حقيقة نفسك.", "الجهل بالخالق يورث وحشة لا تملؤها كل مؤانسات الخلق.", "العولمة الهشة تصنع ضحايا، والتربية الوحيانية تصنع أبطالاً.", "خلوتك بهاتفك هي ضياع، وخلوتك بنفسك هي بداية العلاج.", "الصحة النفسية ليست غياب الألم، بل هي حسن التعامل معه.", "العاقل هو من ربط قلبه بالله، وعمله بالدليل، وحياته بالهدف."],
    practical_applications: ["اختر فعلاً تفعله يومياً (كشرب القهوة أو تصفح فيسبوك) واسأل نفسك 3 مرات: \"لماذا أفعل هذا الآن؟\".", "حدد \"تعلقاً\" واحداً في حياتك تشعر أنه يضغط عليك نفسياً، وابدأ في ممارسة \"الاستقلال بالله\".", "عند سماع خبر \"إسلام مشهور\"، لا تنشره فوراً؛ اسأل نفسك: \"هل أنشره لله أم لأسجل نقطة في صراع الهويات؟\".", "طبق \"حمية رقمية\"؛ امسح تطبيقاً واحداً يستهلك وقتك ويزيد من \"فوضى نفسك\".", "واجه \"مجهولاً\" وجودياً واحداً (كالموت أو الرزق) بالقراءة في نصوص الوحي المتعلقة به.", "عندما تنتقد شخصاً، راقب غريزتك: هل تنتقد للحق، أم لتشعر بالأفضلية عليه؟ كن صادقاً.", "الوثيقة 4 من."],
