    key_points: ["التعقل عملية تبدأ بـ \"الإمساك\" وتنتهي بـ \"العمل الصالح\".", "\"المخادعات\" هي الحجاب الأكبر عن رؤية الحقائق كما هي.", "العلم بلا عمل \"جهالة\"، والعمل بلا علم \"ضلال\".", "دراسة التاريخ ضرورة لفهم \"أصل\" الأفكار التي تشكل مدخلاتنا اليوم.", "\"فك النسب\" يحميك من الانبهار بالأشخاص أو الانغلاق عن الحق.", "القران والسنة هما المعيار \"المهيمن\" على كل إنتاج بشري (خلق، إنسان، قلم)."],
    practical_applications: ["راجع \"خارطة نفسك\" أسبوعياً: ما هي المدخلات الغالبة؟ وكيف تعالجها؟.", "استخدم سؤال \"لماذا؟\" ثلاث مرات متتالية لكشف مخادعاتك في أي قرار مهم.", "ابدأ بقراءة \"أصول\" العلوم (كتاب واحد متقدم) بدلاً من 10 كتب معاصرة سطحية.", "تدرّب على \"الإنصاف\"؛ ابحث عن نقطة حق واحدة عند شخص تختلف معه.", "خصص ربع ساعة لـ \"التبصر\" في أحداث يومك: ما هي السنن الكونية التي تجلت؟.", "حل \"امتحان مادة اقرأ\" (الأسئلة المنتقاة) لتقييم مدى استيعابك للمنهج.", "الوثيقة 6 من."],
