    key_points: ["التبصر بمخادعات النفس هو الجسر الضروري لتعقل الحقائق الكبرى.", "نفسك هي مسؤوليتك الأولى؛ فإذا أصلحتها ملكت الأدوات لإصلاح الآخرين.", "نحن \"أمشاج\" من طين وروح؛ فلا عجب من ضعفنا ولا يأس من قوتنا.", "معرفة \"القراءة العامة\" للنفس تحمينا من صدمات الواقع وانهيار التوقعات.", "الإيثار الحقيقي ثمرة لنفس مشبعة بحقوقها، وليس تضحية بائسة تطلب الثناء.", "الوحي هو المرجعية المطلقة في تعريف \"ماهية النفس\" وما يصلح لها."],
    practical_applications: ["ابدأ فوراً بكتابة \"كراسة قراءتك الخاصة\"؛ دون فيها ظروف نشأتك وأبرز ابتلاءاتك وميولك.", "عندما يُطلب منك فضل أو مساعدة وأنت منهك، قل \"لا\" بأدب لتعطي نفسك حقها من الراحة لتعود للعطاء بقوة.", "في صلاة الجماعة، إذا رأيت فرجاً في الصف، سارع إليه فوراً تطبيقاً لقاعدة \"لا إيثار في القربات\".", "جهز أدواتك لمشروع \"أمشاج\" (مصحف، تطبيق بحث) قبل دخول شهر رمضان.", "عند الشعور بالعجب، ذكّر نفسك بمبدأ \"المخلوقية\" وأنك فقير محتاج لنفسك ولخالقك.", "طبق تدريب \"التحديث بنعمة الله\" يومياً؛ اذكر 3 نعم أنعم الله بها عليك دون خوف من \"جلد الذات\"."],
