    key_points: ["النفس \"مدخلات وعمليات ومخرجات\"؛ فصحح مدخلاتك لترقى مخرجاتك.", "الإمساك والتوقف والصبر هو \"المكبح\" الضروري للانتقال من الحس إلى العقل.", "الخنفشارية هي \"سرطان العقل\" المعاصر؛ فاعرف حدودك ولا تدّعِ ما ليس لك.", "العقل القرآني هو \"إمساك وعمل\"، والذكاء المجرد قد يكون حجة على صاحبه.", "اللغة العربية هي \"بيت العقل\"؛ فبقدر إتقانك لها ينمو تعقلك وفهمك للوحي.", "فهم \"المخلوقية\" يحررك من أوهام الكمال ويضعك في مقام العبودية الصحيح."],
    practical_applications: ["طبق \"تدريب الصمت\" غداً عند الوضوء؛ لا تتكلم مع أحد واستشعر غسل أعضائك من الذنوب.", "أنشئ \"دفتر ونفس\" وقسمه لأقسام: (نصوص مفتاحية، تطبيقات عملية، تساؤلات).", "عندما تجد نفسك تدافع عن \"شخص مشهور\" يخطئ، توقف فوراً واسأل: \"هل أدافع عن الحق أم عن صورتي الذهنية عنه؟\".", "ابدأ بتعلم \"مخارج الحروف\" وقواعد اللغة العربية البسيطة لتقوية آلة التعقل لديك.", "خصص 5 دقائق يومياً قبل النوم لممارسة \"التحديث بنعمة الله\"؛ اذكر 3 نعم واضحة حصلت لك اليوم.", "إذا شعرت بالقلق، عد إلى \"القراءة العامة للنفس\" وذكّر نفسك بأن الضعف والحاجة صفات أصيلة فيك كمخلوق."],
