    key_points: ["لا وجود بلا أثر؛ فاحرص أن يكون أثر وجودك صالحاً مصلحاً لا فاسداً مفسداً.", "إدراكك لمخلوقيتك يبدأ من استشعارك بنعمة وجودك الذي قدره الخالق لك.", "الوجود \"واجب\" للخالق و\"ممكن\" لك؛ فاعرف قدرك وتواضع لمن أوجدك.", "\"جيل التفاهة\" يقتل وجوده بالاستهلاك؛ فابحث عن \"القصد\" لتستعيد كينونتك.", "حريتك تنتهي حيث يبدأ \"أثر وجودك\" في إيذاء الآخرين أو إفساد قيمهم.", "نعمة الوجود تدرك بالبصيرة؛ فالألم عارض، والحياة في أصلها تدفق وعطاء."],
    practical_applications: ["اسأل نفسك يومياً: \"ما هو الأثر الذي تركه وجودي اليوم فيمن حولي؟\"، وحاول تحسينه غداً.", "عندما تشعر بـ \"ضياع القصد\"، اترك هاتفك (الاستهلاك) واجلس في خلوة لتتدبر \"لماذا أوجدني الله في هذا الزمان؟\".", "إذا كنت والداً، راقب أثر \"وجود طفلك\" في مراجعة عاداتك السيئة، واجعل منه دافعاً للتزكية.", "قبل نشر أي محتوى رقمي، فكر في \"أثره الوجودي\" الممتد؛ هل سيبني أم سيهدم في نفوس المتابعين؟.", "عند رؤية شخص مبتلى صابر، ذكّر نفسك بـ \"نعمة الوجود\" الواسعة التي نتجاهلها لانشغالنا بالمنغصات الصغيرة.", "تدرب على \"رفع سقف المعقولات\"؛ توقع من \"النفس الإنسانية\" الضعف والخطأ، لتقابل أخطاء الآخرين بطمأنينة الوجود.", "الوثيقة 7 من."],
