    key_points: ["قراءة النفس هي \"مواجهة السرداب\" بصدق لاستعادة السيطرة على حياتك.", "الاستغناء بالله هو \"الأمان النفسي\" الوحيد في عالم متبدل ومتحول.", "كل مخلوق في حياتك هو \"ميدان اختبار\" وليس غاية في حد ذاته.", "الكتابة اليدوية بالقلم الرصاص هي \"فعل المقاومة\" الأول ضد تشتت النفس.", "الحرية هي \"الخروج من عبودية الخلق\" إلى سعة عبودية الخالق.", "\"أدومها وإن قل\" هو سر الثبات النفسي والتزكية الحقيقية."],
    practical_applications: ["ابدأ اليوم بتخصيص \"نصف ساعة مقدسة\" للكتابة في كراسة قراءة النفس بصدق.", "عند شعورك بالوحدة، تذكر أنك \"جزء من عالم العالمين\" وسبّح مع ما حولك من جماد ونبات.", "مارس \"التورية\" عند كتابة ذكرياتك المؤلمة لضمان الستر والمواجهة في آن واحد.", "صنف ممتلكاتك (هاتف، سيارة) إلى \"مقويات\" و\"موهنات\" وتخلص من الموهن منها.", "مارس \"الاستغناء بالله\" من خلال الامتناع عن طلب المساعدة في أمر بسيط لتعويد نفسك على الكفاية بالله.", "التزم بـ \"أقل القليل\" من العمل الصالح يومياً (مثل ركعتي الوتر) وثبّت هذا الوقت."],
