    key_points: ["الحاجة هي \"اضطرار\"؛ ما تفقد النفس بسببه سعادتها أو بقاءها.", "الضعف والفقر والنقص هي \"مفاتيح\" فهم الحاجات البشرية.", "الوحي هو \"البوصلة\" الوحيدة التي تحدد ما هو حاجة حقيقية وما هو وهم.", "هرم ماسلو يفتقر للبعد الروحي والتراتبية القيمية للوحي.", "التخلية تسبق التحلية في الجسد والروح؛ طهّر وعاءك قبل ملئه.", "\"حاجة الأنس\" ضرورة فطرية؛ والإنسان محتاج والآخر محتاج أيضاً."],
    practical_applications: ["صنف رغباتك اليومية إلى \"حاجات\" (اضطرار) و\"تحسينات\" (زينة) وقلل من الثانية.", "عند شعورك بالعجز، اسأل نفسك: \"هل هذا ضعف أصيل فأتقوى، أم وهن طارئ فأستغفر؟\".", "مارس \"التخلية الروحية\" يومياً من خلال الاستغفار لتطهير روحك من مكدّرات اليوم.", "اختبر \"تحلية جسدك\" بالتنفس العميق والراحة الكافية لتستعين بها على عباداتك.", "ابحث في القرآن عن \"دعاء\" يلامس حاجتك الحالية واجعله وردك اليومي.", "قاوم \"وهم الكمال\" في عملك؛ اطلب الإتقان ولكن اقبل ببشريتك المحدودة."],
