    key_points: ["الوحي هو المعيار الوحيد الصحيح لترتيب أولويات حاجاتك النفسية.", "التبصر بالنفس بصدق هو أول خطوة لعلاج العُجب والغرور.", "كثرة العطاء دون حصانة نفسية تضعف قدرة الإنسان على تحمل أعباء الحياة.", "الفرق بين التوبة وجلد الذات هو وجود \"الرجاء\" في رحمة الله.", "الاستهلاك الزائد يثقل النفس ويجعلك عبداً للمادة لا رباً لها.", "السكينة تتحقق برفع سقف المعقولات وخفض سقف التوقعات من الدنيا."],
    practical_applications: ["حدد ثلاث \"حاجات\" تظنها ضرورية ثم عرضها على معيار الوحي لتكتشف هل هي حاجات أم شهوات.", "خصص عشر دقائق قبل النوم لـ \"جرد ذاتك\" بموضوعية، مبرزاً إيجابياتك لتشكر وسلبياتك لتستغفر.", "قلل عدد القطع في خزانة ملابسك إلى النصف بالتبرع بها، لتشعر بخفة النفس والتحرر من المادة.", "درب نفسك على \"صمت شهوة الكلام\" في مجلس يكثر فيه المديح لتكسر حدة العُجب في نفسك.", "عند الشعور بالندم على خطأ، اقرأ آيات الرحمة فوراً لتمنع تحول الندم إلى \"جلد ذات\" قانط.", "مارس \"التبسيط\" في بيتك؛ تخلص من كل غرض لا تستخدمه ليقل وقت التنظيف ويزيد وقت الأنس."],
