    key_points: ["معرفة الحاجات هي مفتاح \"الهناء\" والرضا في العلاقات الزوجية والأسرية.", "الأنس بالله هو الضمان الوحيد للحرية النفسية في حال فقد الأنس بالبشر.", "الوحي هو \"المسطرة\" الوحيدة التي تحدد حدود العزة والمقام والجمال.", "الهروب إلى \"الغيبيات\" يعطل العلاج النفسي الضروري للأمراض كالوسواس.", "تحقيق \"القيمة\" يكون بإخلاص العمل في الثغر المتاح، وليس بمسمى الوظيفة.", "الزهد في الحرام هو الخطوة الأولى والأهم قبل الزهد في المباحات."],
    practical_applications: ["عند الشعور بالنكد، اسأل نفسك: \"هل ما أطلبه الآن هو حاجة حقيقية أم إثقال فوق الحاجة؟\".", "إذا كنت تعاني من وسواس، توقف عن سؤال المجموعات فوراً واعرض نفسك على مختص نفسي صادق.", "حدد وقتاً يومياً (15 دقيقة) لـ \"الخلوة بالنفس\" دون هاتف، لتتدرب على الأنس بذاتك وخالقك.", "عند الغضب من شخص، تذكر \"سُنن المخلوقية\" (الضعف والنقص) لتتمكن من مسامحته والستر عليه.", "مارس \"الزهد اللحظي\"؛ اختر الطبق الأبسط مرة في الأسبوع لكسر حدة الاعتياد على الرفاهية.", "إذا كنت تفكر في تغيير تخصصك، استشر طبيباً نفسياً لتعرف هل الدافع هو \"شغف حقيقي\" أم \"بحث عن مقام\"."],
