    key_points: ["المُسخرات هي الوسائل، والمنعم هو الغاية؛ فلا تفتن بالوسيلة عن الغاية.", "كل ميزة في نفسك هي \"مسخر\" من الله لك، وليست \"حقاً\" مكتسباً بجهدك.", "اليأس من الخلق هو قمة الحرية، والأنس بالله هو قمة السعادة.", "الرحمة بالخلق واجبة لأنهم \"مسخرون\" مثلك، فقراء إلى الله مثل فقرك.", "تقديم \"النفس\" في شكر النعم يحميك من الاغتراب عن ذاتك والارتهان للاخرين.", "\"سبحان الله\" هي الكلمة التي تجمع بين التعرف على النعمة وتعظيم المنعم."],
    practical_applications: ["ابحث في القران عن كلمات \"سخر\"، \"جعل\"، \"ذلل\" واكتب قائمة بالمسخرات المذكورة لتستشعرها في يومك.", "مارس \"تمرين التحديث\": اكتب 5 نعم في نفسك (ذكاء، صحة، مهارة) وقل: \"الحمد لله الذي أنعم علي بكذا\" بصوت مسموع.", "جرب \"الرحمة بالمسخرات\": تعامل مع هاتفك أو سيارتك أو موظف بسيط برفق شديد اليوم، مستحضراً فكرة \"التسخير\".", "عند رؤية منظر طبيعي، قل \"سبحان الله\" واستمر في التأمل دقيقة كاملة لتختبر شعور \"الأوفيلينج\".", "طبق \"اليأس من الخلق\"؛ إذا تأخر عنك رد أو مساعدة، قل: \"المسخر هو الله\" واطلب منه مباشرة دون سخط على البشر.", "شاهد وثائقياً عن \"الخلية\" أو \"الفضاء\" لتعيد اكتشاف عظمة \"المسخرات\" من حولك وفي داخلك.", "الوثيقة 10 من."],
