    key_points: ["الزهد هو مفتاح الاستمتاع بالمسخرات؛ فمن لم يزهد فيها استعبدته وأذلته.", "الأنس بالآفاق مدد إلهي لا ينقطع، وهو رفيق المؤمن في وحشة الوحدة أو الحصار.", "تصفير عداد النفس يومياً بـ \"سيد الاستغفار\" هو علاج الكآبة والضيق مجهول المصدر.", "الاستجابة الإلهية تتبع كمال الحكمة، وليست قائمة مشتريات نمليها على الخالق.", "العلم النافع هو ما تحول إلى عمل، وما سواه فهو \"فضول معرفي\" يثقل الروح.", "العبودية لله هي الحرية الوحيدة التي تحميك من السقوط تحت أقدام الأنفس والأشياء."],
    practical_applications: ["أنت مطالب بترديد \"سيد الاستغفار\" صباحاً ومساءً بتركيز، كإعلان يومي للتحرر من عبودية الخلق.", "أنتِ ينبغي أن تمارسي \"الزهد الاختياري\" اليوم بترك شيء واحد تحبينه، لتختبري سيادتك على رغباتك.", "أنت مدعو للبحث عن \"أثر رحمة الله\" في حدث سيء مر بك اليوم، لتتدرب على رؤية المسخرات والنعم في المحن.", "أنت مطالب بالتوقف عن متابعة \"ترند\" واحد مشهور لتدرّب نفسك على \"ترك ما لا يعنيك\" عملياً.", "أنتِ كأم، خصصي 15 دقيقة اليوم للحوار مع طفلك حول \"معنى الله\" بعيداً عن أوامر الواجبات المدرسية.", "أنت مطالب بالقيام بـ \"سجدة شكر\" عند شعورك بالصفر الشعوري (الطمانينة)، اعترافاً بفضل الله في سكون الأحوال.", "الوثيقة 11 من.", "إليك أدلة الدراسة الشاملة والمفصلة للمجالس الخمسة الخاصة بفقيه الألم ضمن سلسلة \"ونفس\"، مصاغة وفق المعايير البيداغوجية والشرعية الدقيقة:"],
