    key_points: ["التسليم هو \"مدافعة نشطة\" للقدر بالقدر، بينما الاستسلام هو \"عجز سلبي\" يقود للكآبة.", "\"اكتئاب الإسلاميين\" ناتج عن الرغبة في \"الفردوس الأرضي\" بدلاً من القبول بسنة الابتلاء.", "لا يوجد إنسان \"مسير\" في المعاصي؛ نحن \"مخيرون\" في كل ما كلفنا الله به من مدافعة الهوى.", "المشاعر (حب، كره، خوف، رجاء) هي نباتات تنمو في تربة \"الألم واللذة\" وتحتاج لتهذيب شرعي.", "الترف والرفاهية الزائدة يبنيان \"نفسية هشاشة\" تنهار أمام أبسط أزمات الحياة.", "\"خرافة الشغف\" هي عدو \"المكابدة\" والواجب؛ فالحياة تتطلب صبراً على ما نكره لنصل لما نحب."],
    practical_applications: ["ميز بين \"الاستسلام للواقع\" وبين \"التسليم للخالق\"؛ وجاهد نفسك لتقوم بدور المصلح رغم الألم.", "تدرب على \"البذاذة\" أسبوعياً (مثلاً: اترك لذة معينة، أو تخفف من زينة) لتقوي عضلاتك النفسية.", "عند الشعور بالحزن، ابحث عن \"العمل الصالح المصلح\" لتزاحم به ألمك، ولا تستسلم للانعزال.", "توقف عن البحث عن \"الشغف\" في كل واجب؛ وركز على \"إتقان العمل\" احتساباً للأجر.", "اختبر صدق مشاعرك؛ هل خوفك من الله يمنعك فعلياً من المعصية؟ أم هو مجرد شعور أجوف؟", "في خصومتك القادمة، تعمد \"كظم غيظك\" (ألم وقتي) لتذوق حلاوة \"الانتصار على النفس\" (لذة مآلية)."],
