    key_points: ["الماضي الذي يشدك للخلف بالصور والذكريات الموهنة هو سجن يجب كسر أبوابه.", "من لا يستطيع أن يأكل لقمته بتمهل دون كاميرا، فهو محروم من حقيقة النعمة.", "المكان الذي لا تستطيع العبادة فيه إلا بمكيف وزخرف، هو صنم يباعد بينك وبين الله.", "الزهد ليس فقراً، بل هو قوة تجعلك تمتلك الأشياء ولا تسمح لها بامتلاكك.", "أقصى درجات المرونة هي أن تشعر بأن \"أرض الله واسعة\" وأن قلبك هو موطنك.", "من اعتاد \"أقل القليل\" في الرخاء، كان أثبت الناس قدماً في الشدائد."],
    practical_applications: ["اذهب الآن إلى خزانتك واستخرج 5 قطع (ملابس أو أغراض) لم تستخدمها منذ عام وتصدق بها فوراً لتكسر تعلقك بالمتاع.", "جرب \"الأكل بتمهل\" اليوم؛ اترك هاتفك بعيداً، وامضغ كل لقمة 20 مرة، واشعر بتفاصيل النعمة بوعي كامل.", "صلِّ صلاة الفريضة القادمة في مسجد لم تدخله من قبل، واجلس في مكان غير الذي اعتدت عليه لتكسر إدمانك المكاني.", "احذف تطبيقاً واحداً من تطبيقات التسوق أو \"الفاشن\" التي تستهلك وقتك وتثير فيك شهوة الشراء التي لا تنتهي.", "تعمد المشي في طريق \"غير ممهد\" أو الجلوس في مكان \"غير مكيف\" لمدة نصف ساعة لتدريب جسدك على المرونة.", "إذا شعرت بالحزن من ذكرى ماضية، قم فوراً وصلِّ ركعتين بنية \"شكر الله على ما تعلمته من ذلك الألم\" لتمزح الألم بالعمل."],
