    key_points: ["الفراسة ألمٌ ينجيك من كوارث الغفلة، والجهل راحةٌ توردك المهالك.", "الإنصات هو \"الصدقة\" المعنوية التي تقدمها للمتألمين، وهو أشق من بذل المال.", "من لم يستطع السلام على خصمه، فهو سجين كبره مهما ادعى التدين.", "الداعية الحقيقي هو من يقتل شهوة \"انتصاره\" ليحيي روح \"مخالفه\".", "الإنصاف هو الميزان الذي يفرق بين النفوس العظيمة والنفوس الصغيرة.", "الرحمة الحقيقية قد تلبس ثوب \"القسوة\" الظاهرة، كما يفعل الجراح لإنقاذ المريض."],
    practical_applications: ["في حوارك القادم، لا تقاطع المقابل أبداً، وانتظر 3 ثوانٍ بعد انتهائه من الكلام قبل أن تبدأ ردك.", "سلم اليوم على شخص بينك وبينه \"شحناء\" بسيطة، وانظر في عينيه بابتسامه (سلام المواجهة).", "إذا سُئلت عن أمر تعرفه ولكن هناك من هو أفضل منك فيه، تعمد \"الإحالة\" عليه لتكسر شهوة الظهور في نفسك.", "مارس \"الفراسة\" اليوم؛ لاحظ ملابس أو نبرة صوت 3 أشخاص وحاول تخمين حالتهم النفسية (حزن، قلق، فرح) وتأكد من ذلك بلطف.", "امنع نفسك من \"غيبة\" شخص اختلف معك اليوم، وإذا ذُكر أمامك فاذكر \"خصلة واحدة\" جيدة فيه (الإنصاف).", "مارس \"الانسحاب التربوي\"؛ احرم نفسك (أو من تربيه) من رفاهية واحدة اليوم (كالحلوى أو المكيف) لتقوية عضلات الصبر."],
