    key_points: ["لا تجعلي أذنيك \"سلة نفايات\" لشكاوى الآخرين، وضعي حدوداً تحمي فطرتك.", "\"الناس ليسوا آلهة\"؛ فكرههم أو رضاهم لا ينبغي أن يعطل \"عداد حياتك\".", "\"مساحات التفاهة\" في الحوار هي مهارة ذكية للحفاظ على صلة الرحم المتوترة.", "بناء الإنسان في البيت هو \"العمل الأعظم\" الذي يفوق رتب الطب والهندسة.", "إبانات الصحابة والأنبياء هي النموذج الأسمى للصدق الذي يحرر النفس ويصلح الخلق.", "تتبع مادة (قال، يقول) في القرآن يفتح لك آفاقاً لتعلم \"القول السديد\" والنافع."],
    practical_applications: ["اتفق مع أقاربك المختلفين معك فكرياً على مواضيع \"حيادية\" للحديث فيها أثناء الزيارات.", "إذا بدأت أمك بالشكوى من أبيك، قولي بلطف: \"يا أمي هذا يزعجني، هل يمكننا الحديث في شيء آخر؟\".", "خصص وقتاً يومياً لقراءة قصة نبي من القرآن، وركز على \"الكلمات\" التي استخدمها في حواره.", "إذا شعرتِ بـ \"الاستنزاف\" بين العمل والبيت، أعيدي ترتيب أولوياتك بناءً على \"مركزية البيت\".", "عند التعرض لظلم كببر، اسأل نفسك: \"ماذا سيكون وزنه يوم القنطرة؟\" لتسهل على نفسك المسامحة.", "واجهِ عيوبك بشجاعة؛ إذا كنتِ \"هشة\" نفسياً، فاعترفي بضعفك وابدأي في تقوية صلتك بالله.", "الوثيقة 31 من."],
