    key_points: ["التزكية هي الثمرة النهائية لكل رحلة فقه النفس من \"اقرأ\" إلى \"الهجرة\".", "فقه اللحظة هو عبادتك الآن؛ فلا تضيع خلواتك الإجبارية في تشتيت الجوال.", "الهجرة ليست هروباً، بل هي مفارقة للباطل بنية عدم العودة إليه أبداً.", "اجعل من زيارة القبور \"فورمات\" دورياً لنفسك لتستقيم موازينك في الدنيا.", "احذر \"الهجرة المحرمة\"؛ فترك أهل الصلاح والوالدين هو ضياع لا تزكية.", "الخلوة الصادقة لا تحتاج إلى دراما، بل إلى ورقة وقلم وثلاثية: الله، النفس، الآخر."],
    practical_applications: ["استثمر \"خلوة قضاء الحاجة\" أو \"الوضوء\" للصمت التام واستشعار نعم الله الجسدية عليك.", "طبق \"فقه الآن\" في أول خطبة جمعة قادمة؛ أغلق هاتفك وركز: ما هي الرسالة الموجهة لي شخصياً؟", "نفذ \"هجرة رقمية\" اليوم؛ غادر مجموعة واحدة أو احذف تطبيقاً واحداً تعلم أنه يزيد غفلتك.", "قم بزيارة المقبرة هذا الأسبوع منفرداً؛ قف أمام قبر مفتوح وتخيل أنك بداخله.. ماذا ستتمنى؟", "في خلوتك الليلة قبل النوم، اجرد ملف \"الآخر\": هل ظلمت أحداً؟ هل تواصلت مع والديك ببر؟", "تدرب على الصمت لمدة 10 دقائق يومياً دون أي مشغل خارجي، فقط لتسمع \"صوت نفسك\"."],
