    key_points: ["الحكمة هي بوصلة \"الغريب\"؛ فاعرف متى تنكر بيدك، ومتى بلسانك، ومتى بقلبك وهو أضعف الإيمان.", "رغبة الجنة هي وقود العبودية الصادقة؛ فلا تدع الفلسفات الباردة تطفئ شوقك لنعيم الله.", "رخص الدين يقتله في القلوب؛ فصن مبادئك من أن توضع في سياقات الابتذال.", "التنافس الحقيقي هو مع \"نفسك الأمس\"؛ فاجعل مضمارك لله ولا تلتفت لضجيج المنافسين.", "الصمت عند الأذان هو \"تدريب أركان\" على الإخلاص والتعظيم قبل الدخول في الصلاة.", "بر الوالدين هو الجهاد الأكبر؛ فاجعل من إزعاجهم لك مختبراً للصبر وطلب الأجر."],
    practical_applications: ["في أول اجتماع عائلي، مارس \"الصمت الحكيم\"؛ لا تهاجم أحداً، فقط ابقَ هادئاً وابتسم للحق وأعرض عن اللغو.", "إذا عزمت على ترك عادة سيئة، لا تخبر أحداً؛ اجعلها \"خبيئة\" بينك وبين الله واطلب منه الثبات.", "تدرب على \"ضعفاء في الباطل\"؛ إذا أتيحت لك فرصة غيبة أو سخرية، فادعُ الله فوراً أن يخرس لسانك.", "اجعل لنفسك \"مضماراً\" خاصاً اليوم؛ حدد هدفاً (مثل ختم جزء أو صلة رحم) وأتمه دون أن تنظر لمن أنجز أكثر منك.", "عند رؤية منكر لا تستطيع تغييره، قل في نفسك: \"اللهم إن هذا منكر لا يرضيك\"، وانصرف بهدوء وصيانة لقلبك.", "خصص 5 دقائق بعد صلاة الفجر للصمت التام وتخيل \"الجائزة\" (الجنة) لتستقبل يومك بروح قوية ومتفائلة.", "الوثيقة 17 من."],
