    key_points: ["علو الهمة هو استصغار ما دون الله، وقوة الإرادة هي القدرة على فعل ما تكره للوصول لما تحب.", "\"الشغف\" شرارة جيدة للبداية، لكن \"الانضباط\" هو الوقود الحقيقي للاستمرار والنجاح.", "احذر من شعوذة \"التنمية البشرية\" التي تبيعك أوهام النجاح السهل وتدمر استقرارك النفسي.", "\"تدريبات الألم\" اليومية هي السبيل الوحيد لتقوية إرادتك؛ فلا تنتظر \"المزاج\" المناسب لتعمل.", "الورد اليومي من الوحي هو الضامن الوحيد لعدم انحراف بوصلتك وسط ضجيج المشتتات.", "السعادة الحقيقية تكمن في \"الوفاء بالواجب\" وتحقيق مراد الله، لا في ملاحقة شغف متبدل."],
    practical_applications: ["حدد \"مهنة\" واحدة في حياتك تضعف إرادتك (مثل السكر أو التصفح العبثي) وانقطع عنها أسبوعاً كـ \"تخلية\".", "عندما تشعر بفقدان \"الشغف\" في دراستك أو عملك، ذكر نفسك بأن \"الالتزام بالواجب\" هو عبادة في ذاتها.", "توقف عن متابعة \"المشاهير\" الذين يسوقون لأسلوب حياة لا يشبه قيمك، واستبدلهم بصحبة تعلي همتك.", "ابدأ بـ \"ورد يومي\" ثابت (ولو صفحة واحدة) واعتبره تمريناً على \"الانضباط\" الذي يتجاوز تقلب المزاج.", "واجه نفسك بـ \"مخادعة\" واحدة تمارسها حالياً لتبرير كسل عن عمل ضروري، وابدأ بفعل الممكن الآن.", "مارس \"تدريب ألم\" بسيط اليوم (مثل الاستيقاظ فور رنين المنبه) لتقوية \"عضلة\" الإرادة عندك."],
