    key_points: ["أقل القليل أدومه وإن قل هو سر التغيير النفسي العميق.", "لا خطة بدون تدوين في البدايات لضبط شتات النفس.", "كل يوم لا تزداد فيه علماً (جديداً أو مثبتاً) فأنت مغبون.", "الحاجة هي البوصلة الصحيحة لطلب العلم، وليست الفضول العبثي.", "الإتقان في \"علم الاستخلاف\" (المهنة) فريضة دينية وليست خياراً دنيوياً.", "الخماسية اليومية هي العضلة التي تربي النفس على الانضباط العام."],
    practical_applications: ["دَوِّن أعمالك الثلاثة الأساسية لغدك قبل أن تنام الليلة.", "اقرأ تفسير سورة الفاتحة وآية الكرسي من \"تفسير السعدي\" لتثبيت أصل علمك.", "تأكد من صحة وضوئك وصلاتك بمشاهدة فيديو تعليمي دقيق أو قراءة كتيب فقهي.", "أَلزم نفسك بـ \"ركعتي الضحى\" في وقت الضحى (بعد الشروق بثلث ساعة).", "اجعل لك \"ورداً\" من حديث النبي ﷺ يومياً (حديث واحد على الأقل).", "قل \"لا\" لبرنامج اجتماعي مفاجئ إذا كان سيضيع عليك \"أقل القليل\" المخطط له."],
