    key_points: ["رضا الله هو الغاية الوحيدة التي لا تتركك في شقاء، بينما رضا الناس سراب ينهك الروح.", "أنت مخلوق ناقص وضعيف، وقبول هذا النقص هو أولى خطوات القوة والسكينة النفسية.", "مدخلاتك (ما تراه وتسمعه) هي التي تشكل رغباتك؛ فطهّر نوافذك يطهر قلبك.", "الدنيا لا تساوي عند الله جناح بعوضة، فلا تحملها فوق رأسك فتنكسر رقبتك.", "الإبانة عن حاجتك بصدق تكسر كبرك وتفتح لك أبواب الرحمة مع الخلق.", "اقل القليل المداوم عليه خير من كثير منقطع، وهو الدواء الناجع لوهم الكمال."],
    practical_applications: ["احذف فوراً أي تطبيق على هاتفك يستهلك وقتك دون فائدة حقيقية أو يسبب لك ضيقاً نفسياً بسبب المقارنات.", "إذا شعرت بغضب من موقف تافه، قل لنفسك \"هذه دنيا لا تستحق\" وتوقف عن الرد لمدة دقيقة كاملة.", "خصص 10 دقائق يومياً قبل النوم لـ \"جرد النفس\" وتدوين موقف واحد صدقت فيه مع نفسك وموقف آخر خادعت فيه.", "في المرة القادمة التي تحتاج فيها مساعدة، اطلبها بوضوح دون \"لف ودوران\" واكسر كبر الاستغناء الوهمي.", "انظر إلى والديك اليوم واستحضر \"سلم المخلوقية\"؛ سامحهما على نقص بشريتهما كما تحب أن يسامحك الله.", "ابدأ من الغد في \"أقل قليل\" من ورد قرآني (صفحة واحدة) واثبت عليها مهما كانت الظروف."],
