    key_points: ["أصلح \"بيتك الداخلي\" أولاً، فليس من الحكمة استقبال الزوار في بيت منهار وفوضوي.", "النبي ﷺ مقام \"فوق الأنا\"؛ فلا تعارف يصح ولا أخلاق تستقيم إذا قدمت رأيك على سنته.", "المداهنة هي \"دهان\" الزيف لإرضاء الخلق، والصدق هو \"تجريد\" النفس لإرضاء الخالق.", "الإيثار هو فيض من \"نفس ممتلئة\"، وفاقد الطمانينة لن يمنحها للآخرين حتى يجدها في نفسه.", "التعارف الصادق يبدأ بـ \"تميز الهوية\"؛ فمن لا يعرف من هو، لن يعرف كيف يتعامل مع من حوله.", "الرحمة هي \"مسك الختام\" والغلاف الذي يجعل الاختلاف والحوار والخصومة أفعالاً تزكوية."],
    practical_applications: ["تدرب اليوم على \"فقه التحية\"؛ ألقِ السلام بوضوح وابتسامة على 3 أشخاص لا تعرفهم (حارس، عامل، بائع).", "عندما يطلب منك شخص نصيحة، ابدأ بعبارة \"في نفسي كذا\" لتتدرب على \"الإبانة والتعبير\" بصدق.", "قبل أن تنام، استحضر مقام النبي ﷺ في حياتك واسأل نفسك: \"في أي موقف اليوم قدمت هواي على سنته؟\".", "مارس \"المداراة\" مع شخص يزعجك؛ تلطف به لدفع شره دون أن توافقه على خطئه أو تداهنه في دينه.", "خصص \"وقت خلوة\" (15 دقيقة) بعيداً عن الشاشات لتفكر في \"علاقتك مع الآخرين\" بناءً على ثلاثية عون (عقل، وحي، نظر).", "ابدأ بقراءة مقدمة كتاب \"دستور الأخلاق في القرآن\" لمحمد دراز (أول 18 صفحة) لتفهم الأساس المعرفي لما هو قادم."],
