    key_points: ["الصدق مهارة عملية تبدأ بـ \"الإمساك\" والتوقف عن ضجيج الحياة لسماع صوت الفطرة الحقيقي في خلوة صادقة.", "التناغم بين الفكرة والشعور والسلوك هو جوهر السوية النفسية، وأي خلل في هذا المثلث هو بداية المرض والقلق.", "الوحي هو المرجع النهائي الذي يحدد \"حق النفس\" ويحميها من التيه خلف \"حظوظها\" وأهوائها المقنعة.", "الصدق لا يعني فضح الستر النفسي أمام الناس، بل مواجهة العيوب بشجاعة بين العبد وخالقه وفي محاضن العلاج.", "مراتب الصدق سبعة، وأخطرها \"السعي الفوري\" لأنه الفيصل بين الادعاء العاطفي وبين التغيير العملي الحقيقي.", "تبصرك الصادق بنفسك يمنحك \"فراسة\" في فهم الآخرين ورحمة بضعفهم، لأنك تدرك وحدة العجينة البشرية."],
    practical_applications: ["خصص 15 دقيقة يومياً للصمت التام دون هاتف، وراقب \"صوت النفس\" الذي يظهر في هذا الفراغ.", "عند كل رغبة ملحة، اسأل نفسك بصدق: \"هل هذا حظ لنفسي (هوى) أم حق لها (مصلحة شرعية)؟\".", "إذا أدركت تقصيراً في واجب، فابدأ بأول خطوة إصلاحية الآن (وضوء، اعتذار، حذف تطبيق) ولا تسوف.", "تدرب على قول \"لا أعلم\" في مواقف الوجاهة الاجتماعية لكسر صنم حظ النفس في الظهور المعرفي.", "مارس \"فقه البيان\"؛ عبّر عن مشاعرك الحقيقية للمقربين بأدب في وقتها، وتجنب ترحيل المشاعر المؤدي للأحقاد.", "عند وقوعك في ذنب، استر على نفسك وواجه ربك بالاعتراف الصادق في صلاة الوتر، وضع خطة عملية لعدم العودة."],
