    key_points: ["الصدق مهارة عملية تُكتسب بالمجاهدة، وليست مجرد حالة عاطفية أو ادعاء لساني بالاستقامة.", "\"مرآة الآخر\" (نصيحة أو نقد) هي أداة ربانية لاختبار صدقنا، ويجب قبولها بامتنان ولو جاءت من مقصر.", "التحرر من \"اليأس من الخلق\" هو المفتاح لاتخاذ القرارات الصعبة التي ترضي الله وتغضب الناس.", "الصدق المعرفي يقتضي الإنصاف مع المخالف، والحزن لضلاله بدلاً من الفرح بـ \"قصف جبهته\".", "\"السعي الفوري\" هو الفيصل بين المخادع الذي يسوف وبين الصادق الذي يبرئ ذمته فور تبين الحق.", "الالتزام بالأحكام الشرعية (اللباس، ترك الكسب الحرام) هو أصدق تعبير عن ترويض النفس وكسر صنم الهوى."],
    practical_applications: ["إذا كنت تعمل في مجال لا تتقنه كلياً، فتوقف فوراً وخصص وقتاً لإتقان الأساسيات قبل الاستمرار في الكسب.", "عند الشعور بنشوة غامرة لسقوط مخالف في مناظرة، أمسك نفسك واستغفر، وادعُ له بالهداية لتكسر حظ نفسك.", "إذا أخطأت في معلومة علمية أمام طلابك أو على صفحتك، فبادر بإعلان الخطأ علناً ونشر التصحيح بصدق.", "درب لسانك على قول \"لا أعلم\" في مواقف الوجاهة الاجتماعية لكسر \"وهم الكمال\" والأنفة من الجهل.", "إذا أحسست بضيق من نقد زوجك أو أولادك، فتوقف واسأل بصدق: \"هل في كلامهم حق يجب أن أغيره؟\".", "عند وقوع حادث (مثل سكب الزيت)، اعترف فوراً بمسؤوليتك دون تورية، وتحمل العاقبة لتدريب نفسك على الصدق.", "الوثيقة 28 من."],
